2342 /// Find a constant NewC that has property:
2343 ///   shuffle(NewC, ShMask) = C
2344 /// Returns nullptr if such a constant does not exist e.g. ShMask=<0,0> C=<1,2>
2345 ///
2346 /// A 1-to-1 mapping is not required. Example:
2347 /// ShMask = <1,1,2,2> and C = <5,5,6,6> --> NewC = <poison,5,6,poison>
2348 Constant *InstCombinerImpl::unshuffleConstant(ArrayRef<int> ShMask, Constant *C,
2349                                               VectorType *NewCTy) {
2350   if (isa<ScalableVectorType>(NewCTy)) {
2351     Constant *Splat = C->getSplatValue();
2352     if (!Splat)
2353       return nullptr;
2354     return ConstantVector::getSplat(NewCTy->getElementCount(), Splat);
2355   }
2356 
2357   if (cast<FixedVectorType>(NewCTy)->getNumElements() >
2358       cast<FixedVectorType>(C->getType())->getNumElements())
2359     return nullptr;
2360 
2361   unsigned NewCNumElts = cast<FixedVectorType>(NewCTy)->getNumElements();
2362   PoisonValue *PoisonScalar = PoisonValue::get(C->getType()->getScalarType());
2363   SmallVector<Constant *, 16> NewVecC(NewCNumElts, PoisonScalar);
2364   unsigned NumElts = cast<FixedVectorType>(C->getType())->getNumElements();
2365   for (unsigned I = 0; I < NumElts; ++I) {
2366     Constant *CElt = C->getAggregateElement(I);
2367     if (ShMask[I] >= 0) {
2368       assert(ShMask[I] < (int)NumElts && "Not expecting narrowing shuffle");
2369       Constant *NewCElt = NewVecC[ShMask[I]];
2370       // Bail out if:
2371       // 1. The constant vector contains a constant expression.
2372       // 2. The shuffle needs an element of the constant vector that can't
2373       //    be mapped to a new constant vector.
2374       // 3. This is a widening shuffle that copies elements of V1 into the
2375       //    extended elements (extending with poison is allowed).
2376       if (!CElt || (!isa<PoisonValue>(NewCElt) && NewCElt != CElt) ||
2377           I >= NewCNumElts)
2378         return nullptr;
2379       NewVecC[ShMask[I]] = CElt;
2380     }
2381   }
2382   return ConstantVector::get(NewVecC);
2383 }
