2408   };
2409   Value *V1, *V2, *Offset;
2410   if (match(LHS,
2411             m_Intrinsic<SpliceID>(m_Value(V1), m_Poison(), m_Value(Offset)))) {
2412     // Op(splice(V1, poison, offset), splice(V2, poison, offset))
